.darma-loader-darma-custom-598 {color: var(--loader-color, #0ea5e9);
   width: 50px;
   height: 30px;
   display: grid;
   overflow: hidden;
}
.darma-loader-darma-custom-598:before, .darma-loader-darma-custom-598:after  {
  content: "";
   grid-area: 1/1;
   background: currentColor;
   clip-path: polygon(0 10px,calc(100% - 15px) 10px,calc(100% - 15px) 0,100% 50%,calc(100% - 15px) 100%,calc(100% - 15px) calc(100% - 10px),0 calc(100% - 10px));
   animation: darma-loader-darma-custom-598-l5 1s infinite;
   transform: translate(calc(0% + var(--s,0%)));
}
.darma-loader-darma-custom-598:after  {
  --s:-100%;
}
@keyframes darma-loader-darma-custom-598-l5  {
  80%,100%{transform: translate(calc(100% + var(--s,0%)))}
}

